import { onUnmounted, type Ref } from 'vue'
import { getAudioContextCtor } from '@/lib/env'
import {
    AUDIO_TYPE_THROTTLE_MS,
    AUDIO_TYPE_BASE_FREQ,
    AUDIO_TYPE_FREQ_RANGE,
    AUDIO_TYPE_GAIN,
    AUDIO_TYPE_GAIN_END,
    AUDIO_TYPE_DURATION,
    AUDIO_SUCCESS_START_FREQ,
    AUDIO_SUCCESS_END_FREQ,
    AUDIO_SUCCESS_GAIN,
    AUDIO_SUCCESS_GAIN_END,
    AUDIO_SUCCESS_DURATION,
    AUDIO_FAIL_FREQ_1,
    AUDIO_FAIL_FREQ_2,
    AUDIO_FAIL_FREQ_SHIFT_TIME,
    AUDIO_FAIL_GAIN,
    AUDIO_FAIL_GAIN_END,
    AUDIO_FAIL_DURATION,
} from '@/lib/defaults'

export interface UseAudioEngineReturn {
    playSound: (type: 'type' | 'success' | 'fail') => void
    dispose: () => void
}

export function useAudioEngine(enabled: Ref<boolean>): UseAudioEngineReturn {
    let audioCtx: AudioContext | null = null
    let audioUnavailable = false
    let lastTypeSoundTime = 0

    const getCtx = () => {
        if (!audioCtx && !audioUnavailable) {
            const AudioContextCtor = getAudioContextCtor()
            if (!AudioContextCtor) {
                audioUnavailable = true
                return null
            }

            try {
                audioCtx = new AudioContextCtor()
            } catch {
                audioUnavailable = true
                return null
            }
        }
        return audioCtx
    }

    const playSound = (type: 'type' | 'success' | 'fail') => {
        if (!enabled.value) return
        if (type === 'type') {
            const now = Date.now()
            if (now - lastTypeSoundTime < AUDIO_TYPE_THROTTLE_MS) return
            lastTypeSoundTime = now
        }

        const ctx = getCtx()
        if (!ctx) return

        if (ctx.state === 'suspended') {
            void ctx.resume().catch(() => {})
        }

        try {
            const osc = ctx.createOscillator()
            const gain = ctx.createGain()
            osc.connect(gain)
            gain.connect(ctx.destination)

            osc.onended = () => {
                osc.disconnect()
                gain.disconnect()
            }

            if (type === 'type') {
                osc.type = 'triangle'
                osc.frequency.setValueAtTime(AUDIO_TYPE_BASE_FREQ + Math.random() * AUDIO_TYPE_FREQ_RANGE, ctx.currentTime)
                gain.gain.setValueAtTime(AUDIO_TYPE_GAIN, ctx.currentTime)
                gain.gain.exponentialRampToValueAtTime(AUDIO_TYPE_GAIN_END, ctx.currentTime + AUDIO_TYPE_DURATION)
                osc.start()
                osc.stop(ctx.currentTime + AUDIO_TYPE_DURATION)
            } else if (type === 'success') {
                osc.type = 'sine'
                osc.frequency.setValueAtTime(AUDIO_SUCCESS_START_FREQ, ctx.currentTime)
                osc.frequency.exponentialRampToValueAtTime(AUDIO_SUCCESS_END_FREQ, ctx.currentTime + AUDIO_SUCCESS_DURATION)
                gain.gain.setValueAtTime(AUDIO_SUCCESS_GAIN, ctx.currentTime)
                gain.gain.exponentialRampToValueAtTime(AUDIO_SUCCESS_GAIN_END, ctx.currentTime + AUDIO_SUCCESS_DURATION)
                osc.start()
                osc.stop(ctx.currentTime + AUDIO_SUCCESS_DURATION)
            } else if (type === 'fail') {
                osc.type = 'square'
                osc.frequency.setValueAtTime(AUDIO_FAIL_FREQ_1, ctx.currentTime)
                osc.frequency.setValueAtTime(AUDIO_FAIL_FREQ_2, ctx.currentTime + AUDIO_FAIL_FREQ_SHIFT_TIME)
                gain.gain.setValueAtTime(AUDIO_FAIL_GAIN, ctx.currentTime)
                gain.gain.exponentialRampToValueAtTime(AUDIO_FAIL_GAIN_END, ctx.currentTime + AUDIO_FAIL_DURATION)
                osc.start()
                osc.stop(ctx.currentTime + AUDIO_FAIL_DURATION)
            }
        } catch {
            audioUnavailable = true
        }
    }

    const dispose = () => {
        void audioCtx?.close().catch(() => {})
        audioCtx = null
    }

    onUnmounted(() => {
        dispose()
    })

    return { playSound, dispose }
}

import { ref, toValue, type MaybeRefOrGetter, type Ref } from 'vue'

export type ValidationState = 'default' | 'success' | 'error'
export type ValidationRule<TValue> = (value: TValue) => boolean | string
export type ValidateOn = 'input' | 'blur' | 'submit'

export interface UseFormFieldValidationOptions<TValue = string> {
    rules?: MaybeRefOrGetter<ValidationRule<TValue>[]>
    validateOn?: MaybeRefOrGetter<ValidateOn>
    defaultErrorMessage?: MaybeRefOrGetter<string>
    onValidationChange?: (state: ValidationState, message?: string) => void
}

export interface UseFormFieldValidationReturn<TValue = string> {
    validationState: Ref<ValidationState>
    errorMessage: Ref<string>
    validate: (value: TValue) => boolean
    reset: () => void
    shouldValidateOnInput: () => boolean
    shouldValidateOnBlur: () => boolean
}

export function useFormFieldValidation<TValue = string>(options: UseFormFieldValidationOptions<TValue> = {}): UseFormFieldValidationReturn<TValue> {
    const validationState = ref<ValidationState>('default')
    const errorMessage = ref<string>('')

    function validate(value: TValue): boolean {
        const rules = toValue(options.rules) ?? []
        if (rules.length === 0) {
            if (validationState.value !== 'default') {
                validationState.value = 'default'
                errorMessage.value = ''
                options.onValidationChange?.('default')
            }
            return true
        }

        let isOk = true
        let errText = ''
        for (const rule of rules) {
            const result = rule(value)
            if (result !== true) {
                isOk = false
                errText = typeof result === 'string'
                    ? result
                    : toValue(options.defaultErrorMessage) ?? 'Invalid value'
                break
            }
        }

        const prevState = validationState.value
        if (!isOk) {
            validationState.value = 'error'
            errorMessage.value = errText
            if (prevState !== 'error') {
                options.onValidationChange?.('error', errText)
            }
        } else {
            validationState.value = 'success'
            errorMessage.value = ''
            if (prevState !== 'success') {
                options.onValidationChange?.('success')
            }
        }

        return isOk
    }

    function reset() {
        if (validationState.value === 'default') return
        validationState.value = 'default'
        errorMessage.value = ''
        options.onValidationChange?.('default')
    }

    const shouldValidateOnInput = () => toValue(options.validateOn) === 'input'
    const shouldValidateOnBlur = () => toValue(options.validateOn) === 'blur'

    return {
        validationState,
        errorMessage,
        validate,
        reset,
        shouldValidateOnInput,
        shouldValidateOnBlur,
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

